&lt;%* let qcFileName = await tp.system.prompt(&ldquo;Note Title&rdquo;) let titleName = qcFileName await tp.file.rename(&lsquo;index&rsquo;) let baseFolder = &quot;&quot; let newFolder = ${baseFolder}/${titleName}/ await tp.file.move(newFolder + index); let title = titleName
// 获取 Obsidian 根 vault 路径 let vaultPath = app.vault.adapter.basePath;
// 构建封面保存路径 let imagePath = ${vaultPath}/${newFolder}/cover.jpg;
// 创建目录（如果不存在） const fs = require(&lsquo;fs&rsquo;); const dirs = imagePath.substring(0, imagePath.lastIndexOf(&rsquo;/&rsquo;));
if (!fs.existsSync(dirs)) { fs.mkdirSync(dirs, { recursive: true }); }
// 下载图片 await tp.user.download_image(&ldquo;http://api.mtyqx.cn/api/random.php", imagePath);
let description = &quot;&rdquo; let slug = &quot;&quot; let date = &quot;&quot; let image = ${newFolder}/cover.jpg let categories = &quot;&quot; let tags = &quot;&quot; let weight = &quot;&quot;
setTimeout(() =&gt; { app.fileManager.processFrontMatter(tp.config.target_file, frontmatter =&gt; { frontmatter[&ldquo;title&rdquo;] = title; frontmatter[&ldquo;description&rdquo;] = description; frontmatter[&ldquo;slug&rdquo;] = slug; frontmatter[&ldquo;date&rdquo;] = date; frontmatter[&ldquo;image&rdquo;] = image; frontmatter[&ldquo;categories&rdquo;] = categories; frontmatter[&ldquo;tags&rdquo;] = tags; frontmatter[&ldquo;weight&rdquo;] = 1; }) }, 200) -%&gt;
